import{_ as a,o as i,c as l,a2 as e}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"验证目标功能是否容易找到","description":"","frontmatter":{"title":"验证目标功能是否容易找到","stage":"intermediate","direction":"interaction-design","tags":["information-architecture","findability"]},"headers":[],"relativePath":"03-interaction-design/notes/04-information-architecture/05-findability-validation.md","filePath":"03-interaction-design/notes/04-information-architecture/05-findability-validation.md","lastUpdated":1784542968000}'),d={name:"03-interaction-design/notes/04-information-architecture/05-findability-validation.md"};function r(o,t,n,h,s,c){return i(),l("div",null,[...t[0]||(t[0]=[e(`<h1 id="验证目标功能是否容易找到" tabindex="-1">验证目标功能是否容易找到 <a class="header-anchor" href="#验证目标功能是否容易找到" aria-label="Permalink to &quot;验证目标功能是否容易找到&quot;">​</a></h1><p>可发现性验证检查用户能否从给定起点识别正确入口并到达目标。它不等于“页面有没有曝光”，也不等于“搜索能不能返回结果”。验证必须先定义目标、起点、允许路径和成功条件，再组合结构测试、原型任务、生产行为和技术检查。</p><h2 id="能力边界与前置知识" tabindex="-1">能力边界与前置知识 <a class="header-anchor" href="#能力边界与前置知识" aria-label="Permalink to &quot;能力边界与前置知识&quot;">​</a></h2><p>本文适用于导航重组前后的验证、目标功能上线前的查找测试，以及生产环境中持续发现退化。</p><p>前置知识：</p><ul><li>已建立页面和功能的稳定目标 ID。</li><li>已完成<a href="./04-navigation-boundaries">导航机制责任边界</a>。</li><li>能区分入口点击、到达目标和完成业务任务。</li><li>能按角色、平台、入口和新旧用户分群。</li></ul><p>本文不通过偏好问题判断结构优劣。“更喜欢 A”不能证明能在 A 中找到目标。可发现性也不是完整可用性：用户找到退款设置后仍可能无法理解或完成退款。</p><h2 id="定义可发现性" tabindex="-1">定义可发现性 <a class="header-anchor" href="#定义可发现性" aria-label="Permalink to &quot;定义可发现性&quot;">​</a></h2><p>一个有效查找任务包含：</p><p>[ FindabilityTask = Start + Goal + AvailableCues + AllowedMechanisms + Success ]</p><ul><li><code>Start</code>：角色、页面、对象上下文、设备与已有权限。</li><li><code>Goal</code>：用户语言描述的结果，不泄露导航标签。</li><li><code>AvailableCues</code>：起点实际可见的名称、分组、搜索范围和位置。</li><li><code>AllowedMechanisms</code>：是否允许搜索、外部文档、浏览器后退或旧书签。</li><li><code>Success</code>：到达规范目标，并能依据标题、内容或状态确认目标正确。</li></ul><p>缺少任一项，成功率就可能无法解释。例如“找到报表权限”没有指定组织级还是项目级权限，也没有指定测试角色，结果会把不同目标混在一起。</p><h2 id="四层证据模型" tabindex="-1">四层证据模型 <a class="header-anchor" href="#四层证据模型" aria-label="Permalink to &quot;四层证据模型&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    T[&quot;无界面的树结构任务&quot;] --&gt; P[&quot;带标签与布局的原型任务&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P --&gt; R[&quot;真实实现：权限、URL、焦点、错误&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; D[&quot;生产数据：搜索、返回、404、完成&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; H[&quot;形成具体问题假设&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; T</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>四层回答不同问题：</p><table tabindex="0"><thead><tr><th>层级</th><th>能回答</th><th>不能单独回答</th></tr></thead><tbody><tr><td>树结构任务</td><td>分类与标签能否把人带到目标</td><td>视觉层级、响应速度和控件行为</td></tr><tr><td>原型任务</td><td>布局与交互线索是否支持查找</td><td>真实权限、路由和数据延迟</td></tr><tr><td>真实实现</td><td>完整状态和工程契约是否成立</td><td>大规模自然使用中的分布</td></tr><tr><td>生产数据</td><td>哪些路径和失败大量发生</td><td>用户为何做出某次选择</td></tr></tbody></table><p>不要用某一层替代其他层。树测试通过不代表键盘用户能操作折叠菜单；点击日志显示“到达”也不代表到达的是用户想要的目标。</p><h2 id="设计可判定的查找任务" tabindex="-1">设计可判定的查找任务 <a class="header-anchor" href="#设计可判定的查找任务" aria-label="Permalink to &quot;设计可判定的查找任务&quot;">​</a></h2><h3 id="使用目标语言-避免答案泄露" tabindex="-1">使用目标语言，避免答案泄露 <a class="header-anchor" href="#使用目标语言-避免答案泄露" aria-label="Permalink to &quot;使用目标语言，避免答案泄露&quot;">​</a></h3><p>若目标导航标签是“访问控制”，任务不要写“请找到访问控制”。可以写：“你需要让同事只能查看项目，不能修改内容。你会从哪里开始？”</p><p>任务描述应包含现实前提，但不包含：</p><ul><li>目标菜单原词。</li><li>应点击的区域名称。</li><li>测试者在真实场景不会知道的内部对象。</li><li>带倾向的“你觉得是否容易”。</li></ul><h3 id="固定起点与结束点" tabindex="-1">固定起点与结束点 <a class="header-anchor" href="#固定起点与结束点" aria-label="Permalink to &quot;固定起点与结束点&quot;">​</a></h3><p>每个任务记录：</p><table tabindex="0"><thead><tr><th>字段</th><th>示例</th></tr></thead><tbody><tr><td>任务 ID</td><td><code>find-project-readonly-role</code></td></tr><tr><td>角色</td><td>项目管理员</td></tr><tr><td>起点</td><td>项目 Alpha 概览</td></tr><tr><td>数据条件</td><td>已有 8 名成员</td></tr><tr><td>目标 ID</td><td><code>project-role-policy</code></td></tr><tr><td>规范 URL</td><td><code>/projects/alpha/access/roles</code></td></tr><tr><td>允许机制</td><td>导航；第二轮允许搜索</td></tr><tr><td>成功条件</td><td>到达只读角色策略页并指出作用范围</td></tr><tr><td>失败条件</td><td>到组织角色、成员详情或帮助文档</td></tr></tbody></table><p>“指出作用范围”能防止参与者碰巧落到同名页面却没有识别错误。</p><h3 id="覆盖代表性任务" tabindex="-1">覆盖代表性任务 <a class="header-anchor" href="#覆盖代表性任务" aria-label="Permalink to &quot;覆盖代表性任务&quot;">​</a></h3><p>至少包含：</p><ul><li>高频任务。</li><li>低频高后果任务。</li><li>深层目标。</li><li>多处存在相近名称的目标。</li><li>只能由特定角色看到的目标。</li><li>从通知、搜索或旧深链开始的目标。</li><li>错误、删除或无权限后的恢复任务。</li></ul><p>不要只测试团队刚刚改动、且最容易成功的入口。</p><h2 id="树结构测试" tabindex="-1">树结构测试 <a class="header-anchor" href="#树结构测试" aria-label="Permalink to &quot;树结构测试&quot;">​</a></h2><p>树结构测试移除视觉样式和页面内容，只保留分类标签与层级，让测试者选择认为能到达目标的分支。它适合隔离分类和命名问题。</p><h3 id="结果类型" tabindex="-1">结果类型 <a class="header-anchor" href="#结果类型" aria-label="Permalink to &quot;结果类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>结果</th><th>定义</th><th>诊断价值</th></tr></thead><tbody><tr><td>直接成功</td><td>未离开正确路径即到达目标</td><td>标签与归属支持首次判断</td></tr><tr><td>间接成功</td><td>走错后返回，最终到达目标</td><td>结构可恢复但存在竞争分支</td></tr><tr><td>失败</td><td>结束于错误节点或放弃</td><td>目标不可辨识或归属不符合预期</td></tr><tr><td>跳过</td><td>任务条件无效或技术故障</td><td>不应计入成功率分母</td></tr></tbody></table><p>直接成功率：</p><p>[ DirectSuccess = \\frac{DirectSuccessCount}{ValidAttempts} ]</p><p>总成功率：</p><p>[ TotalSuccess = \\frac{DirectSuccessCount + IndirectSuccessCount}{ValidAttempts} ]</p><p>两者不能合并成一个数字后丢失路径信息。直接成功低、总成功高通常表示可恢复但首次分类线索弱。</p><h3 id="首次选择分布" tabindex="-1">首次选择分布 <a class="header-anchor" href="#首次选择分布" aria-label="Permalink to &quot;首次选择分布&quot;">​</a></h3><p>记录每个任务第一次进入哪个顶级分支。若正确分支得到 55%，另一个分支得到 40%，总体成功率即使较高，也说明两个标签竞争。需要检查：</p><ul><li>两个分组是否使用不同分类维度。</li><li>任务是否天然跨对象。</li><li>错误分支是否需要交叉入口。</li><li>目标名称是否在多个地方承诺相同结果。</li></ul><h3 id="路径而非只有均值" tabindex="-1">路径而非只有均值 <a class="header-anchor" href="#路径而非只有均值" aria-label="Permalink to &quot;路径而非只有均值&quot;">​</a></h3><p>保存匿名化选择序列，例如：</p><p><code>项目 → 成员 → 返回 → 设置 → 访问控制</code></p><p>分析共同错误转移：</p><ul><li>哪个节点首次分流。</li><li>返回后选择了什么。</li><li>是否在同两组之间循环。</li><li>是否到达目标前经过无信息的单子节点。</li></ul><p>一条长路径可能每步都合理；一条短路径也可能碰巧成功。必须结合选择理由和目标确认判断。</p><h2 id="原型与真实实现任务" tabindex="-1">原型与真实实现任务 <a class="header-anchor" href="#原型与真实实现任务" aria-label="Permalink to &quot;原型与真实实现任务&quot;">​</a></h2><p>树结构通过后，在原型或实现中加入：</p><ul><li>视觉层级与响应式布局。</li><li>展开、折叠、Tabs 和搜索交互。</li><li>加载、空、错误、无权限与删除状态。</li><li>页面标题、当前项、面包屑和 URL。</li><li>键盘焦点与屏幕阅读器信息。</li></ul><h3 id="观察点" tabindex="-1">观察点 <a class="header-anchor" href="#观察点" aria-label="Permalink to &quot;观察点&quot;">​</a></h3><ol><li>用户首次注视或键盘到达哪些入口。</li><li>首次选择是否正确。</li><li>错误后能否判断发生了什么。</li><li>返回是否保留起点上下文。</li><li>到达后能否确认对象、范围和权限正确。</li><li>目标操作是否可继续，不因入口不同产生不同状态。</li></ol><p>时间指标从任务呈现并确认理解后开始，到达且确认目标时结束。区分主动操作时间与系统等待，避免把慢接口误判为信息架构问题。</p><h2 id="指标定义与解释" tabindex="-1">指标定义与解释 <a class="header-anchor" href="#指标定义与解释" aria-label="Permalink to &quot;指标定义与解释&quot;">​</a></h2><h3 id="核心指标" tabindex="-1">核心指标 <a class="header-anchor" href="#核心指标" aria-label="Permalink to &quot;核心指标&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>分子</th><th>分母</th><th>用途</th><th>常见误读</th></tr></thead><tbody><tr><td>任务成功率</td><td>到达并确认正确目标的任务</td><td>有效任务尝试</td><td>判断能否找到</td><td>把碰巧到达计为成功</td></tr><tr><td>首次选择正确率</td><td>首选进入正确主分支</td><td>有效任务尝试</td><td>定位分类竞争</td><td>忽略起点不同</td></tr><tr><td>间接成功率</td><td>绕路后成功</td><td>有效任务尝试</td><td>判断恢复成本</td><td>与直接成功混合</td></tr><tr><td>错误分支率</td><td>首次进入指定错误分支</td><td>有效任务尝试</td><td>比较标签竞争</td><td>只看最常见错误</td></tr><tr><td>主动查找时间</td><td>排除系统等待的操作时间</td><td>成功或全部尝试，需明确</td><td>观察效率</td><td>只报告均值</td></tr><tr><td>放弃率</td><td>明确停止且未到达</td><td>有效任务尝试</td><td>发现无恢复路径</td><td>把技术故障算放弃</td></tr></tbody></table><p>报告比例时同时给出计数，例如 <code>14/20</code>，不要只写 70%。样本较小时，百分比波动很大；比较两个方案时应报告区间与任务级分布，不因几个百分点差异宣告胜负。</p><h3 id="完成与到达分开" tabindex="-1">完成与到达分开 <a class="header-anchor" href="#完成与到达分开" aria-label="Permalink to &quot;完成与到达分开&quot;">​</a></h3><p>生产环境中可定义：</p><p>[ TargetArrivalRate = \\frac{SessionsReachedCanonicalTarget}{EligibleFindabilityStarts} ]</p><p>[ TaskCompletionRate = \\frac{CompletedTransactions}{StartedTransactions} ]</p><p>到达目标但未完成，问题可能在表单、权限或业务规则；从未到达，才更直接指向入口、分类、搜索或深链。分母必须明确什么算“开始”，不能用所有登录会话稀释目标任务。</p><h3 id="分群" tabindex="-1">分群 <a class="header-anchor" href="#分群" aria-label="Permalink to &quot;分群&quot;">​</a></h3><p>至少检查：</p><ul><li>新用户与已有使用历史的用户。</li><li>桌面、窄屏与辅助技术路径。</li><li>角色与数据权限。</li><li>从导航、搜索、通知、文档和书签进入。</li><li>中文、英文或其他实际语言。</li><li>新旧导航版本。</li></ul><p>总体改善可能掩盖某一角色的严重退化。</p><h2 id="生产行为数据" tabindex="-1">生产行为数据 <a class="header-anchor" href="#生产行为数据" aria-label="Permalink to &quot;生产行为数据&quot;">​</a></h2><h3 id="导航事件" tabindex="-1">导航事件 <a class="header-anchor" href="#导航事件" aria-label="Permalink to &quot;导航事件&quot;">​</a></h3><p>记录稳定标识，不用显示文字当事件名：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>navigation_version</code></td><td>结构版本</td></tr><tr><td><code>entry_id</code></td><td>被激活的入口</td></tr><tr><td><code>target_id</code></td><td>预期规范目标</td></tr><tr><td><code>start_context</code></td><td>区域、对象和入口类型</td></tr><tr><td><code>role_capability_set</code></td><td>经脱敏后的能力分组</td></tr><tr><td><code>result</code></td><td>到达、403、404、取消、错误</td></tr><tr><td><code>active_time_ms</code></td><td>可选的主动操作时间</td></tr><tr><td><code>platform_class</code></td><td>桌面、窄屏等粗粒度分类</td></tr></tbody></table><p>事件不记录敏感对象名称、搜索原文或完整 URL 查询参数。权限信息使用最小必要的能力分组。</p><h3 id="搜索信号" tabindex="-1">搜索信号 <a class="header-anchor" href="#搜索信号" aria-label="Permalink to &quot;搜索信号&quot;">​</a></h3><ul><li>零结果率必须以有效查询为分母，排除空输入和取消请求。</li><li>查询改写是一次查询后短时间内改变关键词，不等于必然失败。</li><li>结果点击需要结合目标到达和短时返回。</li><li>同义词命中用于检查用户词汇与首选标签差异。</li><li>受限对象在生成建议和结果前过滤，不能先返回再由前端隐藏。</li></ul><p>搜索量上升既可能表示导航难找，也可能表示熟练用户采用更快方式。只有与任务、首次入口、返回和完成共同分析才可形成解释。</p><h3 id="返回与错误" tabindex="-1">返回与错误 <a class="header-anchor" href="#返回与错误" aria-label="Permalink to &quot;返回与错误&quot;">​</a></h3><p>值得排查的组合信号：</p><ul><li>进入目标后数秒内返回，并选择相邻入口。</li><li>在两个分支间来回切换。</li><li>从深链进入 404 后离开站点。</li><li>到 403 后反复搜索同名目标。</li><li>新导航发布后旧 URL 重定向环增加。</li><li>目标到达率不变，但任务完成率下降。</li></ul><p>这些是问题线索，不自动证明原因。</p><h2 id="比较候选结构" tabindex="-1">比较候选结构 <a class="header-anchor" href="#比较候选结构" aria-label="Permalink to &quot;比较候选结构&quot;">​</a></h2><h3 id="同一任务、同一条件" tabindex="-1">同一任务、同一条件 <a class="header-anchor" href="#同一任务、同一条件" aria-label="Permalink to &quot;同一任务、同一条件&quot;">​</a></h3><p>比较 A/B 结构时固定：</p><ul><li>任务措辞与目标。</li><li>起点和角色。</li><li>数据内容。</li><li>是否允许搜索。</li><li>成功判定。</li><li>设备和语言。</li></ul><p>若 A 使用静态树、B 使用完整高保真原型，时间和成功不可直接归因于结构。</p><h3 id="顺序与学习效应" tabindex="-1">顺序与学习效应 <a class="header-anchor" href="#顺序与学习效应" aria-label="Permalink to &quot;顺序与学习效应&quot;">​</a></h3><p>同一个人连续测试两套相近结构会记住目标。可采用不同样本分别测试，或平衡顺序并使用等价任务。报告设计方式，不把学习后的第二轮结果当成纯方案优势。</p><h3 id="决策表" tabindex="-1">决策表 <a class="header-anchor" href="#决策表" aria-label="Permalink to &quot;决策表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>结果</th><th>解释</th><th>下一步</th></tr></thead><tbody><tr><td>A 直接成功更高，完成相同</td><td>A 的首次分类更清晰</td><td>在真实界面验证</td></tr><tr><td>A 成功高但耗时长</td><td>可能分组清晰但路径冗长</td><td>检查单子节点与加载</td></tr><tr><td>两者均失败于同一词</td><td>目标名称或任务模型有问题</td><td>重新定义词汇与对象</td></tr><tr><td>新手 B 好，熟练用户 A 好</td><td>浏览与效率需求不同</td><td>组合导航与搜索</td></tr><tr><td>总体 B 好，低权限角色退化</td><td>权限过滤破坏结构</td><td>修正角色结构后再比较</td></tr></tbody></table><h2 id="案例一-验证-报表权限-能否找到" tabindex="-1">案例一：验证“报表权限”能否找到 <a class="header-anchor" href="#案例一-验证-报表权限-能否找到" aria-label="Permalink to &quot;案例一：验证“报表权限”能否找到&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>企业报表产品同时有组织权限、项目成员和单份报表分享。旧导航把三者都命名为“权限”。候选方案把它们分别归入：</p><ul><li>组织设置 → 角色与权限。</li><li>项目 → 成员访问。</li><li>报表详情 → 分享与访问。</li></ul><p>建立三个任务：</p><ol><li>限制某同事在整个组织只能查看。</li><li>将外包成员从项目 Alpha 移除。</li><li>只把季度报表分享给一名审计员。</li></ol><h3 id="树结构结果" tabindex="-1">树结构结果 <a class="header-anchor" href="#树结构结果" aria-label="Permalink to &quot;树结构结果&quot;">​</a></h3><p>任务 3 的目标是报表详情中的“分享与访问”。若大量首次选择进入“组织设置”，记录错误分支和返回序列。进一步检查任务描述是否明确“只影响这一份报表”，以及“分享与访问”是否能预测对象范围。</p><p>候选修正不是在三个地方都加“报表权限”，而是：</p><ul><li>在组织权限页明确其作用范围。</li><li>从报表空分享状态提供上下文入口。</li><li>搜索“报表权限”返回带对象类型与范围的结果。</li></ul><h3 id="实现验证" tabindex="-1">实现验证 <a class="header-anchor" href="#实现验证" aria-label="Permalink to &quot;实现验证&quot;">​</a></h3><p>使用组织所有者、项目管理员和报表编辑者：</p><ul><li>从首页导航完成三个任务。</li><li>从报表通知深链进入后查找分享入口。</li><li>撤销组织管理权限后复测搜索与侧边分组。</li><li>在窄屏和键盘路径中确认当前项、展开状态和焦点。</li></ul><p>到达错误范围但看到同名“权限”不算成功。到达正确页面后，测试者必须指出变更影响的是组织、项目还是单份报表。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若生产数据只记录“点击权限”，无法区分三个目标，发布后不能验证修正。事件必须使用稳定 <code>entry_id</code> 与 <code>target_id</code>，同时记录作用范围；显示名称可改，分析口径不随文案漂移。</p><h2 id="案例二-验证电商类目与站内搜索的互补" tabindex="-1">案例二：验证电商类目与站内搜索的互补 <a class="header-anchor" href="#案例二-验证电商类目与站内搜索的互补" aria-label="Permalink to &quot;案例二：验证电商类目与站内搜索的互补&quot;">​</a></h2><h3 id="输入-1" tabindex="-1">输入 <a class="header-anchor" href="#输入-1" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>配件商城新增“USB-C 扩展坞”。候选分类有：</p><ul><li>电脑配件 → 扩展坞。</li><li>连接设备 → 转换与扩展。</li></ul><p>用户可能使用“扩展坞”“拓展坞”“转接器”“dock”等词。目标不是选最受欢迎标签，而是验证在浏览和检索两条路径下能否到达正确商品集合。</p><h3 id="测试设计" tabindex="-1">测试设计 <a class="header-anchor" href="#测试设计" aria-label="Permalink to &quot;测试设计&quot;">​</a></h3><p>浏览任务：“笔记本只有一个 USB-C 接口，你需要同时连接显示器、网线和键盘。你会在哪个分类寻找？”</p><p>搜索任务使用相同需求，但允许输入关键词。成功条件是到达能筛选接口与视频输出的扩展坞集合，不是打开任意转接线商品。</p><p>记录：</p><ul><li>浏览首次分支与最终类目。</li><li>搜索原词的受控分类，不保留可识别个人的信息。</li><li>零结果、同义词改写和结果类型。</li><li>到达集合后是否能确认接口需求。</li><li>错误进入普通 USB 转接头后的恢复。</li></ul><h3 id="方案与输出" tabindex="-1">方案与输出 <a class="header-anchor" href="#方案与输出" aria-label="Permalink to &quot;方案与输出&quot;">​</a></h3><p>若浏览路径在两个分支明显分裂，而搜索多种同义词都能稳定到达，可采用：</p><ul><li>规范归属为“电脑配件 → 扩展坞”。</li><li>“连接设备”提供交叉入口，但不复制商品集合。</li><li>搜索索引维护替代词与拼写形式。</li><li>结果显示“扩展坞”首选名称和所属类目。</li></ul><p>分类页 URL 和商品集合保持一个规范目标，交叉入口不产生第二套 SEO 页面、库存筛选或分析口径。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>发布后比较同一商品范围的目标到达率、零结果率、错误类目短时返回和加购前的规格筛选。按移动端与桌面分群，因为窄屏类目折叠可能改变浏览表现。</p><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>如果“dock”搜索成功率高，不能据此把所有导航改成英文。搜索服务已知词查找，导航服务浏览；应保留目标受众能理解的首选标签，并让搜索承接替代词。</p><h2 id="无障碍与隐私边界" tabindex="-1">无障碍与隐私边界 <a class="header-anchor" href="#无障碍与隐私边界" aria-label="Permalink to &quot;无障碍与隐私边界&quot;">​</a></h2><h3 id="无障碍验证不是组件通过即可" tabindex="-1">无障碍验证不是组件通过即可 <a class="header-anchor" href="#无障碍验证不是组件通过即可" aria-label="Permalink to &quot;无障碍验证不是组件通过即可&quot;">​</a></h3><p>在真实页面检查：</p><ul><li>导航区域有可区分名称。</li><li>只用键盘能到达所有入口并离开复合控件。</li><li>当前项、展开与选中状态可程序化确定。</li><li>链接目的能从文本或程序化上下文判断。</li><li>深链加载后页面标题和焦点说明新位置。</li><li>200% 文本缩放及窄屏下，焦点不被固定区域完全遮挡。</li></ul><p>招募或自测条件要覆盖实际会使用辅助技术的人；自动检查只能发现部分语义与状态错误。</p><h3 id="数据最小化" tabindex="-1">数据最小化 <a class="header-anchor" href="#数据最小化" aria-label="Permalink to &quot;数据最小化&quot;">​</a></h3><p>搜索词可能包含姓名、订单号、健康或财务信息。生产观测应：</p><ul><li>默认不保存原始查询，优先保存受控词类、长度和结果类型。</li><li>设置访问范围、保留周期和删除机制。</li><li>对低样本分群抑制展示，避免识别个人。</li><li>不在分析工具中发送完整 URL、对象标题或权限详情。</li><li>将性能分析与安全审计目的分开。</li></ul><h2 id="调试顺序" tabindex="-1">调试顺序 <a class="header-anchor" href="#调试顺序" aria-label="Permalink to &quot;调试顺序&quot;">​</a></h2><p>发现“找不到”时按外向内排查：</p><ol><li>任务目标是否唯一，作用范围是否明确。</li><li>入口标签是否承诺正确目的地。</li><li>分类是否使用用户在起点已知的维度。</li><li>权限过滤是否留下空分组或移除唯一父级。</li><li>当前项、标题、面包屑与 URL 是否一致。</li><li>搜索索引是否新鲜、同义词是否映射、结果是否先鉴权。</li><li>深链、后退和返回是否保持上下文。</li><li>埋点是否把不同入口和目标错误合并。</li></ol><p>不要先凭总体点击率改位置。</p><h2 id="失败注入" tabindex="-1">失败注入 <a class="header-anchor" href="#失败注入" aria-label="Permalink to &quot;失败注入&quot;">​</a></h2><ol><li>删除目标对象后从未读通知进入。</li><li>撤销权限后使用缓存搜索建议。</li><li>让新旧导航同时存在，检查事件版本。</li><li>让搜索索引延迟 30 分钟。</li><li>从没有浏览器历史的新标签打开深链。</li><li>把目标标签替换为长文本和第二语言。</li><li>使移动端导航在任务中途切换断点。</li><li>使目标接口失败但导航正常加载。</li></ol><p>每种故障分别判断“找不到目标”“找到但不可用”“无权限”“对象不存在”和“系统错误”，不能汇总为一个失败状态。</p><h2 id="综合练习-建立可发现性基线" tabindex="-1">综合练习：建立可发现性基线 <a class="header-anchor" href="#综合练习-建立可发现性基线" aria-label="Permalink to &quot;综合练习：建立可发现性基线&quot;">​</a></h2><p>选择一个至少含 40 个目标、3 个角色、全局搜索和移动导航的产品区域，完成：</p><ol><li>12 个不泄露答案的查找任务。</li><li>每项任务的起点、目标 ID、允许机制和成功判定。</li><li>树结构的直接成功、间接成功、错误分支与路径序列。</li><li>真实实现中的键盘、窄屏、权限和错误测试。</li><li>生产事件字典与隐私边界。</li><li>一个候选改版的同口径比较。</li><li>发布后回归阈值与回滚条件。</li></ol><p>验收标准：</p><ul><li>成功必须包含到达并确认正确范围。</li><li>比例同时报告分子、分母和无效任务。</li><li>树、原型、实现和生产数据的结论边界明确。</li><li>结果按关键角色、平台和入口分群。</li><li>搜索词与 URL 中的敏感信息没有进入分析系统。</li><li>至少一个失败假设通过结构或实现修正后重新验证。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/multiple-ways" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 2.4.5 Multiple Ways</a>（访问日期：2026-07-18）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/link-purpose-in-context.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 2.4.4 Link Purpose (In Context)</a>（访问日期：2026-07-18）</li><li><a href="https://www.gov.uk/service-manual/measuring-success/measuring-the-success-of-your-service" target="_blank" rel="noreferrer">GOV.UK Service Manual：Measuring the Success of Your Service</a>（访问日期：2026-07-18）</li><li><a href="https://www.gov.uk/service-manual/measuring-success/measuring-completion-rate" target="_blank" rel="noreferrer">GOV.UK Service Manual：Measuring Completion Rate</a>（访问日期：2026-07-18）</li><li><a href="https://designsystem.digital.gov/components/side-navigation/accessibility-tests/" target="_blank" rel="noreferrer">U.S. Web Design System：Side Navigation Accessibility Tests</a>（访问日期：2026-07-18）</li></ul>`,144)])])}const b=a(d,[["render",r]]);export{u as __pageData,b as default};
